                      sx={{
                        position: "absolute",
                        bottom: 0,
                        right: 0,
                        width: "8px",
                        height: "8px",
                        borderRadius: "50%",
                        backgroundColor: person.online ? "#10b981" : "#6b7280",
                        border: `2px solid ${isDark ? "#1a1a1a" : "#fff"}`,
                      }}
                    />
                  </Box>
                  <Box>
                    <Box
                      sx={{
                        fontSize: "13px",
                        fontWeight: "500",
                        marginBottom: "2px",
                      }}
                    >
                      {person.name}
                    </Box>
                    <Box
                      sx={{
                        display: "flex",
                        alignItems: "center",
                        gap: "6px",
                        fontSize: "11px",
                        color: isDark ? "#666" : "#999",
                      }}
                    >
                      <Box component="span">{person.role}</Box>
                      <Box
                        sx={{
                          width: "2px",
                          height: "2px",
                          borderRadius: "50%",
                          backgroundColor: person.online ? "#10b981" : "#6b7280",
                        }}
                      />
                      <Box component="span">
                        {person.online ? "Online" : "Offline"}
                      </Box>
                    </Box>
                  </Box>
                </Box>
              ))}
            </Box>
          )}
        </AnimatePresence>
      </Box>
    </Box>
  );
};

export default CustomRenderAutocomplete;

