import React, { useMemo } from "react";
import { Box, Typography } from "@mui/material";
import { motion } from "motion/react";

const MotionBox = motion.create(Box);

const MovingShapes = () => {
  const shapes = useMemo(() => {
    const gradients = [
      { start: "#00C853", end: "#B2FF59" },
      { start: "#FF4B2B", end: "#FF416C" },
      { start: "#36D1DC", end: "#5B86E5" },
    ];

    return Array.from({ length: 8 }, (_, index) => ({
      id: index,
      size: [60, 80, 100, 120][index % 4],
      gradient: gradients[index % gradients.length],
      borderRadius: index % 2 === 0 ? "50%" : "30%",
      duration: 12 + index * 1.5,
      left: `${(index * 25) % 100}%`,
      top: `${(index * 35) % 100}%`,
    }));
  }, []);

  return (
    <MotionBox
      sx={{
        width: "100%",
        height: "100%",
        background: "linear-gradient(45deg, #4E65FF, #92EFFD)",
        position: "relative",
        overflow: "hidden",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
      }}
    >
      {shapes.map((shape) => (
        <MotionBox
          key={shape.id}
          sx={{
            position: "absolute",
            width: shape.size,
            height: shape.size,
            borderRadius: shape.borderRadius,
            background: `linear-gradient(135deg, ${shape.gradient.start}, ${shape.gradient.end})`,
            opacity: 0.4,
            filter: "blur(4px)",
            boxShadow: "0 0 20px rgba(0,0,0,0.1)",
          }}
          animate={{
            x: ["-20%", "120%"],
            y: ["-20%", "120%"],
            rotate: [0, 360],
          }}
          transition={{
            duration: shape.duration,
            repeat: Infinity,
            repeatType: "reverse",
            ease: "linear",
          }}
          style={{
            left: shape.left,
            top: shape.top,
          }}
        />
      ))}
      <Typography
        variant="h4"
        sx={{
          color: "#fff",
          zIndex: 1,
          fontWeight: 500,
        }}
      >
        Moving Shapes
      </Typography>
    </MotionBox>
  );
};

export default MovingShapes;

