import React, { useState, useCallback, useEffect } from "react";
import { Box, Typography, IconButton } from "@mui/material";
import { motion, AnimatePresence } from "motion/react";
import { LuPlay, LuPause } from "react-icons/lu";

const MotionBox = motion.create(Box);

const imageSlidesContent = [
  {
    id: 1,
    image: "https://images.unsplash.com/photo-1682685797661-9e0c87f59c60?w=800",
    title: "Quantum Computing",
    description: "Revolutionizing computational possibilities",
  },
  // ... more slides
];

const ParallaxCarousel = () => {
  const [active, setActive] = useState(0);
  const [direction, setDirection] = useState(1);
  const [autoplay, setAutoplay] = useState(true);

  const handleNext = useCallback(() => {
    setDirection(1);
    setActive((prev) => (prev + 1) % imageSlidesContent.length);
  }, []);

  useEffect(() => {
    let timeout;
    if (autoplay) {
      timeout = setTimeout(handleNext, 5000);
    }
    return () => clearTimeout(timeout);
  }, [autoplay, handleNext, active]);

  return (
    <Box sx={{ position: "relative", width: "100%", height: 400, overflow: "hidden", borderRadius: 4 }}>
      <AnimatePresence initial={false} custom={direction}>
        <MotionBox
          key={active}
          initial={{ x: direction > 0 ? "100%" : "-100%" }}
          animate={{ x: 0 }}
          exit={{ x: direction > 0 ? "-100%" : "100%" }}
          transition={{ duration: 0.5, ease: "easeInOut" }}
          sx={{
            position: "absolute",
            width: "100%",
            height: "100%",
            backgroundImage: `url(${imageSlidesContent[active]?.image})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
          }}
        >
          <Box
            sx={{
              position: "absolute",
              inset: 0,
              background: "linear-gradient(45deg, rgba(0,0,0,0.7) 0%, rgba(0,0,0,0.3) 100%)",
              display: "flex",
              flexDirection: "column",
              justifyContent: "center",
              p: { md: 6, xs: 3 },
              color: "white",
            }}
          >
            <Typography variant="h6">{imageSlidesContent[active]?.title}</Typography>
            <Typography variant="body1">{imageSlidesContent[active]?.description}</Typography>
          </Box>
        </MotionBox>
      </AnimatePresence>
      <Box
        sx={{
          position: "absolute",
          bottom: 40,
          left: 0,
          right: 0,
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          gap: 2,
          zIndex: 1,
        }}
      >
        <IconButton
          onClick={() => setAutoplay(!autoplay)}
          sx={{
            color: "white",
            bgcolor: "rgba(255,255,255,0.1)",
            "&:hover": { bgcolor: "rgba(255,255,255,0.2)" },
          }}
        >
          {autoplay ? <LuPause /> : <LuPlay />}
        </IconButton>
        {imageSlidesContent.map((_, index) => (
          <Box
            key={index}
            component={motion.div}
            animate={{
              scale: active === index ? 1 : 0.8,
              opacity: active === index ? 1 : 0.5,
            }}
            transition={{ duration: 0.2 }}
            sx={{
              width: active === index ? 24 : 12,
              height: 4,
              borderRadius: 2,
              bgcolor: "white",
              cursor: "pointer",
              transition: "width 0.3s ease",
            }}
            onClick={() => setActive(index)}
          />
        ))}
      </Box>
    </Box>
  );
};

export default ParallaxCarousel;

