import React, { useState, useCallback } from "react";
import { Box, Typography, IconButton, Paper } from "@mui/material";
import { motion, AnimatePresence } from "motion/react";
import { LuArrowLeft, LuArrowRight } from "react-icons/lu";

const MotionPaper = motion.create(Paper);

const CardCarousel = () => {
  const [active, setActive] = useState(0);

  const handleNext = useCallback(() => {
    setActive((prev) => (prev + 1) % imageSlidesContent.length);
  }, []);

  const handlePrev = useCallback(() => {
    setActive((prev) => (prev - 1 + imageSlidesContent.length) % imageSlidesContent.length);
  }, []);

  return (
    <Box sx={{ position: "relative", width: "100%", height: 400, overflow: "hidden", borderRadius: 4, perspective: "1000px" }}>
      <AnimatePresence>
        {imageSlidesContent.map((slide, index) => {
