              {days.map((day, index) => (
                <Box
                  key={`${day.date.getTime()}-${index}`}
                  sx={getDayStyle(day)}
                  onClick={() => handleDateClick(day.date)}
                  onMouseEnter={(e) => {
                    if (
                      day.isCurrentMonth &&
