                      !isInRange(day.date)
                    ) {
                      e.currentTarget.style.backgroundColor = "transparent";
                    }
                  }}
                >
                  {day.day}
                </Box>
              ))}
            </Box>
          </Box>
        )}
      </Box>
    </Box>
  );
};

export default PresetsDatePicker;

