        size="small"
        sx={{ borderRadius: 0 }}
      >
        <RxChevronLeft
          style={{ color: textColor, fontSize: isMobile ? 16 : 20 }}
        />
      </IconButton>
      {getPageNumbers(currentPage, totalPages)
        .slice(0, 5)
        .map((page, index) =>
          page === "..." ? (
            <Typography
              key={`ellipsis-${index}`}
              color={secondaryColor}
              px={0.5}
            >
              ...
            </Typography>
          ) : (
            <motion.div
              key={`page-${page}`}
