      <IconButton
        onClick={handleNextPage}
        disabled={currentPage === totalPages}
        size="small"
        sx={{ borderRadius: 0 }}
      >
        <RxChevronRight
          style={{ color: textColor, fontSize: isMobile ? 16 : 20 }}
        />
      </IconButton>
      <IconButton
        onClick={handleLastPage}
        disabled={currentPage === totalPages}
        size="small"
        sx={{ borderRadius: 0 }}
      >
        <RxDoubleArrowRight
          style={{ color: textColor, fontSize: isMobile ? 16 : 20 }}
        />
      </IconButton>
    </Box>
  );
};

export default CompactPagination;

