          value={rowsPerPage}
          onChange={handleRowsPerPageChange}
          size="small"
          sx={{ minWidth: 100 }}
          IconComponent={RxChevronDown}
        >
          {[10, 25, 50, 100].map((num) => (
            <MenuItem key={num} value={num}>
              {num}
            </MenuItem>
          ))}
        </Select>
        <Typography variant="body2">
          {start}-{end} of {totalPages * rowsPerPage}
        </Typography>
      </Box>
    </Box>
  );
};

