      {status}
    </Box>
  );

  return (
    <MotionPaper
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        overflow: "hidden",
        bgcolor: "background.paper",
