import React, { useState, useEffect } from "react";
import {
  Box,
  TextField,
  Typography,
  useTheme,
} from "@mui/material";
import { motion, AnimatePresence } from "motion/react";

const OTPInput = () => {
  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const [otpValues, setOtpValues] = useState(Array(6).fill(""));
  const [isFocused, setIsFocused] = useState(false);
  const [placeholderIndex, setPlaceholderIndex] = useState(0);

  const placeholders = [
    "Enter verification code",
    "6-digit code",
    "Security code",
  ];

  const colors = {
    background: isDark ? "#121212" : "#ffffff",
    border: isDark ? "#333333" : "#e0e0e0",
    text: isDark ? "#ffffff" : "#212121",
    textSecondary: isDark ? "#b0b0b0" : "#757575",
    addon: isDark ? "#1e1e1e" : "#f5f5f5",
  };

  useEffect(() => {
    if (!isFocused && !otpValues.some(val => val)) {
      const interval = setInterval(() => {
        setPlaceholderIndex((prev) => (prev + 1) % placeholders.length);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [isFocused, otpValues]);

  return (
    <Box sx={{ position: "relative", width: "100%" }}>
      <Box
        sx={{
          display: "flex",
          gap: { xs: 1, sm: 1.5 },
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        {otpValues.map((digit, index) => (
          <React.Fragment key={index}>
            <motion.div
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.12, delay: index * 0.03 }}
              whileHover={{ y: -2 }}
              whileTap={{ scale: 0.98 }}
            >
              <TextField
                inputProps={{
                  maxLength: 1,
                  style: {
                    textAlign: "center",
                    fontSize: "16px",
                    fontWeight: 500,
                    padding: "10px 0",
                  },
                  autoComplete: "one-time-code",
                }}
                value={digit}
                onChange={(e) => {
                  const newValue = e.target.value.replace(/[^0-9]/g, "");
                  if (newValue.length <= 1) {
                    const newOtpValues = [...otpValues];
                    newOtpValues[index] = newValue;
                    setOtpValues(newOtpValues);
                    if (newValue && index < 5) {
                      document
                        .querySelector(`input[data-index="${index + 1}"]`)
                        ?.focus();
                    }
                  }
                }}
                onPaste={(e) => {
                  e.preventDefault();
                  const paste = e.clipboardData
                    .getData("text")
                    .replace(/[^0-9]/g, "")
                    .slice(0, 6);
                  if (paste) {
                    const digits = paste.split("");
                    setOtpValues([...digits, ...Array(6 - digits.length).fill("")]);
                  }
                }}
                onKeyDown={(e) => {
                  if (e.key === "Backspace" && !digit && index > 0) {
                    document
                      .querySelector(`input[data-index="${index - 1}"]`)
                      ?.focus();
                  }
                }}
                onFocus={() => setIsFocused(true)}
                onBlur={() => setIsFocused(false)}
                sx={{
                  width: { xs: 40, sm: 46 },
                  height: { xs: 40, sm: 46 },
                  "& .MuiOutlinedInput-root": {
                    borderRadius: "8px",
                    backgroundColor: digit ? colors.addon : colors.background,
                    "& fieldset": {
                      borderColor: colors.border,
                      borderWidth: "1px",
                    },
                    "&:hover fieldset": { borderColor: colors.border },
                    "&.Mui-focused fieldset": {
                      borderColor: colors.border,
                      borderWidth: "1px",
                    },
                  },
                  "& .MuiInputBase-input": { color: colors.text },
                }}
                inputRef={(input) =>
                  input?.setAttribute("data-index", String(index))
                }
              />
            </motion.div>

            {index === 2 && (
              <Box
                sx={{
                  display: "flex",
                  alignItems: "center",
                  height: { xs: 40, sm: 46 },
                }}
              >
                <Box
                  sx={{
                    width: 8,
                    height: 1.5,
                    backgroundColor: colors.textSecondary,
                    borderRadius: 1,
                    opacity: 0.4,
                  }}
                />
              </Box>
            )}
          </React.Fragment>
        ))}
      </Box>

      <Box
        sx={{
          display: "flex",
          justifyContent: "center",
          mt: 2,
          gap: 0.5,
        }}
      >
        {otpValues.map((digit, index) => (
          <motion.div
            key={index}
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ duration: 0.12 }}
          >
            <Box
              sx={{
                width: 6,
                height: 6,
                borderRadius: "50%",
                backgroundColor: digit
                  ? (isDark ? "#ffffff" : "#000000")
                  : (isDark ? "#333333" : "#e0e0e0"),
              }}
            />
          </motion.div>
        ))}
      </Box>

      {!isFocused && !otpValues.some(val => val) && (
        <Box
          sx={{
            position: "absolute",
            top: -34,
            left: "50%",
            transform: "translateX(-50%)",
            pointerEvents: "none",
            zIndex: 1,
          }}
        >
          <AnimatePresence mode="wait">
            <motion.div
              key={placeholderIndex}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              transition={{ duration: 0.18, ease: "easeOut" }}
            >
              <Typography
                variant="body2"
                sx={{
                  color: colors.textSecondary,
                  fontSize: "14px",
                  textAlign: "center",
                }}
              >
                {placeholders[placeholderIndex]}
              </Typography>
            </motion.div>
          </AnimatePresence>
        </Box>
      )}
    </Box>
  );
};

export default OTPInput;

