import React, { useState, useMemo, useRef, useEffect, useCallback } from "react";
import { Typography, useTheme, Box, TextField, InputAdornment, IconButton } from "@mui/material";
import { LuClock, LuChevronUp, LuChevronDown } from "react-icons/lu";

const TwentyFourHourTimePicker = () => {
  const [selectedTime, setSelectedTime] = useState({
    hour: "06",
    minute: "00",
  });
  const [isOpen, setIsOpen] = useState(false);
  const [pickerPosition, setPickerPosition] = useState("bottom");

  const containerRef = useRef(null);
  const pickerRef = useRef(null);
  const rafRef = useRef(null);

  const theme = useTheme();
  const isDark = theme.palette.mode === "dark";

  const calculatePosition = useCallback(() => {
    if (!containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const viewportHeight = window.innerHeight;
    const pickerHeight = 320;

    const spaceBelow = viewportHeight - rect.bottom;
    const spaceAbove = rect.top;

    const newPosition =
      spaceBelow < pickerHeight && spaceAbove > pickerHeight ? "top" : "bottom";
    setPickerPosition(newPosition);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target) &&
        pickerRef.current &&
        !pickerRef.current.contains(event.target)
      ) {
        setIsOpen(false);
      }
    };

    const handleScroll = () => {
      if (isOpen) {
        setIsOpen(false);
      }
    };

    if (isOpen) {
      document.addEventListener("mousedown", handleClickOutside, {
        passive: true,
      });
      window.addEventListener("scroll", handleScroll, {
        passive: true,
        capture: true,
      });
      rafRef.current = requestAnimationFrame(calculatePosition);
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      window.removeEventListener("scroll", handleScroll, true);
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }
    };
  }, [isOpen, calculatePosition]);

  useEffect(() => {
    const handleResize = () => {
      if (isOpen) {
        if (rafRef.current) {
          cancelAnimationFrame(rafRef.current);
        }
        rafRef.current = requestAnimationFrame(calculatePosition);
      }
    };

    window.addEventListener("resize", handleResize, { passive: true });
    return () => {
      window.removeEventListener("resize", handleResize);
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }
    };
  }, [isOpen, calculatePosition]);

  const handleTimeChange = useCallback((field, value) => {
    if (value === "") {
      setSelectedTime((prev) => ({
        ...prev,
        [field]: "",
      }));
      return;
    }

    let numValue = value.replace(/\\D/g, "");

    if (field === "hour") {
      let num = parseInt(numValue);
      if (num > 23) {
        numValue = "23";
      } else if (num < 0 && numValue.length === 2) {
        numValue = "00";
      }
    } else {
      let num = parseInt(numValue);
      if (num > 59) {
        numValue = "59";
      }
    }

    setSelectedTime((prev) => ({
      ...prev,
      [field]: numValue,
    }));
  }, []);

  const handleIncrement = useCallback((field) => {
    setSelectedTime((prev) => {
      const current = parseInt(prev[field]) || 0;
      let newValue;

      if (field === "hour") {
        newValue = current === 23 ? 0 : current + 1;
      } else {
        newValue = current === 59 ? 0 : current + 1;
      }

      return {
        ...prev,
        [field]: newValue.toString().padStart(2, "0"),
      };
    });
  }, []);

  const handleDecrement = useCallback((field) => {
    setSelectedTime((prev) => {
      const current = parseInt(prev[field]) || 0;
      let newValue;

      if (field === "hour") {
        newValue = current === 0 ? 23 : current - 1;
      } else {
        newValue = current === 0 ? 59 : current - 1;
      }

      return {
        ...prev,
        [field]: newValue.toString().padStart(2, "0"),
      };
    });
  }, []);

  const formatTime = useCallback(() => {
    const hour = selectedTime.hour || "00";
    const minute = selectedTime.minute || "00";
    return `${hour}:${minute}`;
  }, [selectedTime]);

  const handleBlur = useCallback((e, field) => {
    let value = e.target.value;
    if (value === "") {
      const defaultValue = "00";
      handleTimeChange(field, defaultValue);
    } else if (value.length === 1) {
      setSelectedTime((prev) => ({
        ...prev,
        [field]: value.padStart(2, "0"),
      }));
    }
  }, [handleTimeChange]);

  const renderTimeInput = useCallback((field, label) => (
    <Box
      sx={{
        display: "flex !important",
        flexDirection: "column !important",
        alignItems: "center !important",
        gap: "4px !important",
      }}
    >
      <IconButton
        onClick={() => handleIncrement(field)}
        disableRipple
        sx={{
          p: "2px !important",
          borderRadius: "4px !important",
          color: `${isDark ? "#fff" : "#000"} !important`,
          bgcolor: "transparent !important",
